mapper.delete:
DELETE FROM sys_data_permission
WHERE role_id = #{roleId}
AND business_type = #{businessType}

mapper.select:
SELECT DISTINCT dp.business_id FROM sys_data_permission dp
INNER JOIN sys_user_role ur ON dp.role_id = ur.role_id
WHERE ur.user_id = #{userId}
AND dp.business_type = #{businessType}
